import React, { useState } from 'react'
import { makeStyles } from '@material-ui/styles'
import { Container, Grid } from '@material-ui/core'

const useStyle = makeStyles(theme => {
  return{
  root: {
    display: 'flex'
  },
  content: {
    justifyContent: 'center',
    maxWidth: '900px',
    height: '500px',
alignItems: 'center'
  },
  subjectBackground: {
    background: '#162276',
    color: 'white',
    width: '100%'
  }
}
})

export default function StudentFeed() {
  const classes = useStyle()

  const [subjects, setSubjects] = useState([
    { title: 'Web Development', body: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.', instructor: 'Phil Cajurao', id: 1 },
    { title: 'Web Design', body: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.', instructor: 'Nicolas Sumagaysay', id: 2 },
    { title: 'JavaScript Programming', body: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.', instructor: 'Phil Cajurao', id: 3 },
    { title: 'Calculus', body: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.', instructor: 'Jomari Dacles', id: 4 },
    { title: 'Arduino', body: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.', instructor: 'Jomari Dacles', id: 5 },
    { title: 'Numerical Methods', body: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.', instructor: 'Jomari Dacles', id: 6 },
    { title: 'Engineering Basics', body: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.', instructor: 'Phil Cajurao', id: 7 },
    { title: 'Graphic Designing', body: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.', instructor: 'Nicolas Sumagaysay', id: 8 },
    { title: 'Python Programming', body: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.', instructor: 'Phil Cajurao', id: 9 },
    { title: 'Art App', body: 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.', instructor: 'Nicolas Sumagaysay', id: 10 },
])

  return (
    <div className={classes.root}>
            <Container>
                <Grid container spacing={7}>
                    {subjects.map(subject => (
                        <Grid item xs={12} sm={6} lg={3} key={subject.id}>
                            <SubjectCards subject={subject} />
                        </Grid>
                    ))}
                </Grid>
            </Container>
    </div>
  )
}
